{
  "name": "multilang-video-learner",
  "version": "2.0.0",
  "description": "多语言视频学习软件",
  "author": "单夫纯律�?,
  "copyright": "Copyright © 2026 单夫纯律�? All Rights Reserved.",
  "main": "main.js",
  "scripts": {
    "start": "electron .",
    "obfuscate": "node obfuscate.js",
    "prebuild": "node obfuscate.js",
    "build": "electron-builder"
  },
  "devDependencies": {
    "electron": "^30.0.0",
    "electron-builder": "^25.1.8",
    "javascript-obfuscator": "^5.3.0"
  },
  "dependencies": {
    "better-sqlite3": "^11.0.0"
  },
  "build": {
    "appId": "com.shanfuchun.multilang-learner",
    "productName": "多语言视频学习",
    "copyright": "Copyright © 2026 单夫纯律�? All Rights Reserved.",
    "directories": {
      "output": "dist"
    },
    "files": [
      "package.json",
      "node_modules/**/*",
      {
        "from": "obfuscated",
        "to": ".",
        "filter": ["main.js", "renderer.js"]
      },
      "index.html",
      "styles.css",
      "ai_config.json"
    ],
    "extraResources": [
      {
        "from": "bin",
        "to": "bin",
        "filter": ["**/*"]
      }
    ],
    "win": {
      "target": [
        {
          "target": "nsis",
          "arch": ["x64"]
        }
      ],
      "icon": "icon.ico",
      "legalTrademarks": "单夫纯律�?保留一切权�?
    },
    "nsis": {
      "oneClick": false,
      "allowToChangeInstallationDirectory": true,
      "installerLanguages": ["zh_CN"],
      "language": "2052",
      "createDesktopShortcut": true,
      "createStartMenuShortcut": true,
      "shortcutName": "多语言视频学习",
      "license": "LICENSE.txt",
      "installerIcon": "icon.ico",
      "uninstallerIcon": "icon.ico",
      "installerHeaderIcon": "icon.ico"
    }
  }
}

const { app, BrowserWindow, ipcMain, dialog } = require('electron');
const path = require('path');
const { spawn } = require('child_process');
const fs = require('fs');
const https = require('https');
const http = require('http');

let mainWindow;
let db = null;
let currentLangGlobal = 'en';

const BIN_DIR = app.isPackaged
  ? path.join(process.resourcesPath, 'bin')
  : path.join('E:', '视频下载器具', 'bin');
const YTDLP = path.join(BIN_DIR, 'yt-dlp.exe');
const FFMPEG_DIR = BIN_DIR;
const USER_DATA = app.isPackaged ? path.join(app.getPath('userData')) : __dirname;
const DOWNLOADS = path.join(USER_DATA, 'downloads');
const AI_CONFIG_FILE = path.join(USER_DATA, 'ai_config.json');

// 6家AI预设: 国外3�?+ 国内3�?const AI_PROVIDERS = {
  openai:   { name: 'OpenAI',        baseUrl: 'https://api.openai.com/v1',              model: 'gpt-4o-mini' },
  claude:   { name: 'Claude',        baseUrl: 'https://api.anthropic.com/v1',           model: 'claude-sonnet-4-20250514' },
  groq:     { name: 'Groq',          baseUrl: 'https://api.groq.com/openai/v1',         model: 'llama-3.3-70b-versatile' },
  deepseek: { name: 'DeepSeek(深度求索)', baseUrl: 'https://api.deepseek.com/v1',            model: 'deepseek-chat' },
  qwen:     { name: 'Qwen(通义千问)',    baseUrl: 'https://dashscope.aliyuncs.com/compatible-mode/v1', model: 'qwen-plus' },
  zhipu:    { name: 'Zhipu(智谱清言)',   baseUrl: 'https://open.bigmodel.cn/api/paas/v4',  model: 'glm-4-flash' }
};

function loadAIConfig() {
  try {
    if (fs.existsSync(AI_CONFIG_FILE)) return JSON.parse(fs.readFileSync(AI_CONFIG_FILE, 'utf-8'));
  } catch(e) {}
  return { provider: 'deepseek', apiKey: '', baseUrl: '', model: '' };
}
function saveAIConfig(cfg) { fs.writeFileSync(AI_CONFIG_FILE, JSON.stringify(cfg, null, 2)); }

// 通用AI调用 (OpenAI兼容格式, Claude单独处理)
function callAI(prompt) {
  return new Promise((resolve) => {
    const cfg = loadAIConfig();
    if (!cfg.apiKey) { resolve(null); return; }

    const preset = AI_PROVIDERS[cfg.provider] || {};
    const baseUrl = cfg.baseUrl || preset.baseUrl || '';
    const model = cfg.model || preset.model || '';
    if (!baseUrl) { resolve(null); return; }

    const isClaude = cfg.provider === 'claude';
    const urlObj = new URL(isClaude ? baseUrl + '/messages' : baseUrl + '/chat/completions');
    const isHttps = urlObj.protocol === 'https:';

    let body, headers;
    if (isClaude) {
      body = JSON.stringify({
        model, max_tokens: 1024,
        messages: [{ role: 'user', content: prompt }]
      });
      headers = {
        'Content-Type': 'application/json',
        'x-api-key': cfg.apiKey,
        'anthropic-version': '2023-06-01'
      };
    } else {
      body = JSON.stringify({
        model, max_tokens: 1024,
        messages: [
          { role: 'system', content: '你是一个专业的多语言词典和语言学习助手。所有释义、翻译、解释必须使用准确的中文。对英语单词，请给出准确的中文对应词义，不要音译�? },
          { role: 'user', content: prompt }
        ]
      });
      headers = {
        'Content-Type': 'application/json',
        'Authorization': 'Bearer ' + cfg.apiKey
      };
    }

    const opts = {
      hostname: urlObj.hostname, port: urlObj.port || (isHttps ? 443 : 80),
      path: urlObj.pathname, method: 'POST', headers
    };

    const client = isHttps ? https : http;
    const req = client.request(opts, (res) => {
      let data = '';
      res.on('data', d => data += d);
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          if (isClaude) {
            resolve(json.content?.[0]?.text || null);
          } else {
            resolve(json.choices?.[0]?.message?.content || null);
          }
        } catch(e) { resolve(null); }
      });
    });
    req.on('error', () => resolve(null));
    req.setTimeout(15000, () => { req.destroy(); resolve(null); });
    req.write(body);
    req.end();
  });
}

const LANGUAGES = {
  en: { name: '英语', sub: 'en', tts: 'en-US' },
  ja: { name: '日语', sub: 'ja', tts: 'ja-JP' },
  ko: { name: '韩语', sub: 'ko', tts: 'ko-KR' },
  ru: { name: '俄语', sub: 'ru', tts: 'ru-RU' },
  th: { name: '泰语', sub: 'th', tts: 'th-TH' },
  vi: { name: '越南�?, sub: 'vi', tts: 'vi-VN' },
  ms: { name: '马来�?, sub: 'ms', tts: 'ms-MY' },
  id: { name: '印尼�?, sub: 'id', tts: 'id-ID' },
  ar: { name: '阿拉伯语', sub: 'ar', tts: 'ar-SA' },
  pt: { name: '葡萄牙语', sub: 'pt', tts: 'pt-BR' },
  es: { name: '西班牙语', sub: 'es', tts: 'es-ES' },
  fr: { name: '法语', sub: 'fr', tts: 'fr-FR' },
  de: { name: '德语', sub: 'de', tts: 'de-DE' },
  hi: { name: '印地�?, sub: 'hi', tts: 'hi-IN' }
};

function initDB() {
  const dbPath = path.join(__dirname, 'stardict.db');
  if (fs.existsSync(dbPath)) {
    try {
      const Database = require('better-sqlite3');
      db = new Database(dbPath, { readonly: true });
      db.pragma('journal_mode = WAL');
    } catch (e) { console.error('ECDICT加载失败:', e.message); }
  }
}

function createWindow() {
  mainWindow = new BrowserWindow({
    width: 1100, height: 850, minWidth: 900, minHeight: 700,
    backgroundColor: '#0a0a1a',
    webPreferences: { nodeIntegration: true, contextIsolation: false, webSecurity: false }
  });
  mainWindow.loadFile('index.html');
}

app.whenReady().then(() => {
  initDB();
  if (!fs.existsSync(DOWNLOADS)) fs.mkdirSync(DOWNLOADS, { recursive: true });
  createWindow();
});
app.on('window-all-closed', () => { if (process.platform !== 'darwin') app.quit(); });

// ===== IPC =====

ipcMain.handle('get-languages', () => LANGUAGES);
ipcMain.handle('get-ai-providers', () => AI_PROVIDERS);
ipcMain.handle('get-ai-config', () => loadAIConfig());
ipcMain.handle('save-ai-config', (_, cfg) => { saveAIConfig(cfg); return true; });
ipcMain.handle('set-current-lang', (_, lang) => { currentLangGlobal = lang; });
ipcMain.handle('test-ai-connection', async (_, cfg) => {
  try {
    // 临时保存配置再测�?    saveAIConfig(cfg);
    const result = await callAI('请回�?连接成功"四个�?);
    if (result) return { success: true, message: result.slice(0, 100) };
    return { success: false, message: 'API 无响应，请检�?Key 和服务商设置' };
  } catch(e) { return { success: false, message: e.message }; }
});

// 下载视频+字幕
ipcMain.handle('download-video', async (_, url, lang) => {
  const subLang = LANGUAGES[lang]?.sub || 'en';
  return new Promise((resolve) => {
    const infoArgs = ['--dump-json', '--no-playlist', url];
    if (fs.existsSync(path.join(FFMPEG_DIR, 'ffmpeg.exe'))) infoArgs.unshift('--ffmpeg-location', FFMPEG_DIR);
    const infoProc = spawn(YTDLP, infoArgs);
    let infoOut = '';
    infoProc.stdout.on('data', d => infoOut += d);
    infoProc.on('close', (code) => {
      let title = 'video_' + Date.now();
      if (code === 0) { try { title = JSON.parse(infoOut).title || title; } catch(e) {} }
      const safeName = title.replace(/[<>:"/\\|?*]/g, '_').substring(0, 60);
      const outTemplate = path.join(DOWNLOADS, safeName + '.%(ext)s');
      const args = [
        '--ffmpeg-location', FFMPEG_DIR,
        '-f', 'bestvideo[height<=720]+bestaudio/best[height<=720]/best',
        '--merge-output-format', 'mp4',
        '--write-sub', '--write-auto-sub', '--sub-lang', subLang,
        '--sub-format', 'vtt', '--convert-subs', 'vtt',
        '--no-playlist', '-o', outTemplate, url
      ];
      const proc = spawn(YTDLP, args);
      let stderr = '', maxPercent = 0, streamCount = 0;
      proc.stdout.on('data', (data) => {
        const output = data.toString();
        if (output.includes('Destination:')) streamCount++;
        const matches = output.match(/(\d+\.?\d*)%/g);
        if (matches) {
          let percent = parseFloat(matches[matches.length - 1]);
          if (streamCount >= 2) percent = 50 + percent / 2;
          else if (streamCount === 1) percent = percent / 2;
          if (percent > maxPercent) { maxPercent = percent; mainWindow.webContents.send('download-progress', { percent }); }
        }
        if (output.includes('Merging')) mainWindow.webContents.send('download-progress', { percent: 99 });
      });
      proc.stderr.on('data', d => stderr += d);
      proc.on('close', (code2) => {
        if (code2 !== 0) { resolve({ success: false, error: stderr || '下载失败' }); return; }
        const videoFile = path.join(DOWNLOADS, safeName + '.mp4');
        let subFile = null;
        const possibleSubs = [
          path.join(DOWNLOADS, safeName + '.' + subLang + '.vtt'),
          path.join(DOWNLOADS, safeName + '.vtt'),
        ];
        try {
          for (const f of fs.readdirSync(DOWNLOADS)) {
            if (f.startsWith(safeName) && f.endsWith('.vtt')) possibleSubs.push(path.join(DOWNLOADS, f));
          }
        } catch(e) {}
        for (const p of possibleSubs) { if (fs.existsSync(p)) { subFile = p; break; } }
        resolve({ success: true, videoPath: fs.existsSync(videoFile) ? videoFile : null, subtitlePath: subFile, title: safeName });
      });
      proc.on('error', () => resolve({ success: false, error: 'yt-dlp未找�? }));
    });
  });
});

// ECDICT查词
ipcMain.handle('lookup-word', (_, word) => {
  if (!db) return null;
  try {
    return db.prepare('SELECT word, phonetic, translation, exchange FROM stardict WHERE word = ? COLLATE NOCASE').get(word.toLowerCase().trim()) || null;
  } catch(e) { return null; }
});

// 在线翻译
ipcMain.handle('translate-word', (_, word, fromLang) => {
  return new Promise((resolve) => {
    const url = `https://api.mymemory.translated.net/get?q=${encodeURIComponent(word)}&langpair=${fromLang}|zh`;
    https.get(url, (res) => {
      let data = '';
      res.on('data', d => data += d);
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          resolve({
            translation: json.responseData?.translatedText || null,
            matches: (json.matches || []).slice(0, 3).map(m => ({ segment: m.segment, translation: m.translation }))
          });
        } catch(e) { resolve(null); }
      });
    }).on('error', () => resolve(null));
  });
});

// 在线例句 (多语�?
ipcMain.handle('fetch-examples', (_, word, lang) => {
  if (lang === 'ja') {
    // 日语: jisho.org API
    return new Promise((resolve) => {
      const url = `https://jisho.org/api/v1/search/words?keyword=${encodeURIComponent(word)}`;
      https.get(url, (res) => {
        let data = '';
        res.on('data', d => data += d);
        res.on('end', () => {
          try {
            const json = JSON.parse(data);
            const entry = json.data?.[0];
            if (!entry) { resolve(null); return; }
            const reading = entry.japanese?.[0]?.reading || '';
            const definitions = (entry.senses || []).slice(0, 5).map(s => ({
              partOfSpeech: (s.parts_of_speech || []).join(', '),
              definition: (s.english_definitions || []).join('; ')
            }));
            resolve({ phonetic: reading, definitions, examples: [] });
          } catch(e) { resolve(null); }
        });
      }).on('error', () => resolve(null));
    });
  }
  // 英语: dictionaryapi.dev
  return new Promise((resolve) => {
    const apiLang = lang === 'en' || !lang ? 'en' : lang;
    const url = `https://api.dictionaryapi.dev/api/v2/entries/${apiLang}/${encodeURIComponent(word)}`;
    https.get(url, (res) => {
      let data = '';
      res.on('data', d => data += d);
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          if (!Array.isArray(json)) { resolve(null); return; }
          const entry = json[0], examples = [], definitions = [];
          for (const meaning of (entry.meanings || [])) {
            for (const def of (meaning.definitions || [])) {
              definitions.push({ partOfSpeech: meaning.partOfSpeech, definition: def.definition });
              if (def.example) examples.push(def.example);
            }
          }
          resolve({
            phonetic: entry.phonetic || '',
            audio: entry.phonetics?.find(p => p.audio)?.audio || '',
            definitions: definitions.slice(0, 5),
            examples: examples.slice(0, 5)
          });
        } catch(e) { resolve(null); }
      });
    }).on('error', () => resolve(null));
  });
});

// AI精准翻译单词为中�?ipcMain.handle('ai-translate-word', async (_, word, context) => {
  const langName = LANGUAGES[currentLangGlobal]?.name || '英语';
  const prompt = `�?{langName}单词�?{word}」翻译为准确的中文含义�?{context ? '上下�? "' + context + '"' : ''}只回复中文释义，不要其他内容。多个义项用/分隔。`;
  return await callAI(prompt);
});

// AI智能释义 (根据上下文生成释�?例句)
ipcMain.handle('ai-lookup', async (_, word, lang, context) => {
  const langName = LANGUAGES[lang]?.name || lang;
  const prompt = `请解�?{langName}单词/词组�?{word}」的含义�?${context ? '该词出现在以下句子中: "' + context + '"' : ''}
请用以下格式回答:
【释义】中文释�?如有多个义项用序号标�?
【发音】用国际音标标注发音
【例句】给�?个实用例�?附中文翻�?
【助记】一个简短的记忆技巧`;
  const result = await callAI(prompt);
  return result;
});

// AI智能分析字幕句子
ipcMain.handle('ai-analyze-sentence', async (_, sentence, lang) => {
  const langName = LANGUAGES[lang]?.name || lang;
  const prompt = `请分析以�?{langName}句子，帮助学习者理�?
"${sentence}"
请用以下格式简洁回�?
【翻译】中文翻�?【语法】关键语法点(1-2�?
【重点词汇】列�?-3个重要词汇及释义`;
  return await callAI(prompt);
});

// 列出已下载视�?ipcMain.handle('list-videos', () => {
  try {
    const files = fs.readdirSync(DOWNLOADS);
    return files.filter(f => f.endsWith('.mp4')).map(f => {
      const name = f.replace('.mp4', '');
      const subFile = files.find(s => s.startsWith(name) && s.endsWith('.vtt'));
      return { name, videoPath: path.join(DOWNLOADS, f), subtitlePath: subFile ? path.join(DOWNLOADS, subFile) : null };
    });
  } catch(e) { return []; }
});

ipcMain.handle('read-subtitle', (_, filePath) => {
  try { return fs.readFileSync(filePath, 'utf-8'); } catch(e) { return null; }
});

ipcMain.handle('import-video', async () => {
  const result = await dialog.showOpenDialog(mainWindow, {
    title: '选择视频文件',
    filters: [{ name: '视频文件', extensions: ['mp4', 'mkv', 'avi', 'mov', 'webm', 'wmv'] }],
    properties: ['openFile']
  });
  if (result.canceled || !result.filePaths.length) return null;
  const src = result.filePaths[0];
  const dest = path.join(DOWNLOADS, path.basename(src));
  sendSubtitleStatus('文件导入�?..');
  if (src !== dest && !fs.existsSync(dest)) fs.copyFileSync(src, dest);
  sendSubtitleStatus('字幕文件检测中...');
  // 检查同名字幕文�?  for (const ext of ['.vtt', '.srt']) {
    const subSrc = src.replace(/\.[^.]+$/, ext);
    const subDest = path.join(DOWNLOADS, path.basename(subSrc));
    if (fs.existsSync(subSrc) && !fs.existsSync(subDest)) fs.copyFileSync(subSrc, subDest);
  }
  const subFile = ['.vtt', '.srt'].map(e => dest.replace(/\.[^.]+$/, e)).find(f => fs.existsSync(f));
  sendSubtitleStatus(subFile ? '已找到字幕文件，加载�?..' : '未找到字幕文件，稍后将自动识�?);
  return { videoPath: dest, subtitlePath: subFile || null, name: path.basename(dest, path.extname(dest)) };
});

// 语音识别生成字幕 (调用本地 funasr 服务)
const FUNASR_PYTHON = path.join(require('os').homedir(), 'funasr-venv', 'Scripts', 'python.exe');
const FUNASR_SERVER = path.join(require('os').homedir(), '.clawdbot', 'skills', 'funasr-transcribe', 'scripts', 'server.py');
let funasrProcess = null;

function checkFunasr() {
  return new Promise((resolve) => {
    const req = http.request({ hostname: '127.0.0.1', port: 8765, path: '/health', method: 'GET', timeout: 3000 }, (res) => {
      let d = ''; res.on('data', c => d += c);
      res.on('end', () => resolve(true));
    });
    req.on('error', () => resolve(false));
    req.on('timeout', () => { req.destroy(); resolve(false); });
    req.end();
  });
}

function sendSubtitleStatus(msg) {
  if (mainWindow && !mainWindow.isDestroyed()) mainWindow.webContents.send('subtitle-status', msg);
}

async function ensureFunasr() {
  if (await checkFunasr()) return true;
  sendSubtitleStatus('正在启动语音识别服务...');
  // 启动服务
  if (fs.existsSync(FUNASR_PYTHON) && fs.existsSync(FUNASR_SERVER)) {
    funasrProcess = spawn(FUNASR_PYTHON, [FUNASR_SERVER], { stdio: 'ignore', detached: true });
    funasrProcess.unref();
    // 等待服务就绪，最�?0�?    for (let i = 0; i < 60; i++) {
      await new Promise(r => setTimeout(r, 1000));
      if (await checkFunasr()) {
        sendSubtitleStatus('语音识别服务已就�?);
        return true;
      }
      sendSubtitleStatus(`正在启动语音识别服务... (${i + 1}s)`);
    }
  }
  sendSubtitleStatus('语音识别服务启动失败');
  return false;
}

function transcribeFile(filePath) {
  return new Promise((resolve) => {
    const data = JSON.stringify({ file_path: filePath });
    const req = http.request({
      hostname: '127.0.0.1', port: 8765, path: '/transcribe',
      method: 'POST', headers: { 'Content-Type': 'application/json' }
    }, (res) => {
      let body = '';
      res.on('data', d => body += d);
      res.on('end', () => {
        try { resolve(JSON.parse(body)); } catch(e) { resolve(null); }
      });
    });
    req.on('error', () => resolve(null));
    req.setTimeout(600000, () => { req.destroy(); resolve(null); });
    req.write(data);
    req.end();
  });
}

const SEGMENT_DURATION = 600; // 10分钟一�?
ipcMain.handle('generate-subtitle', async (_, videoPath) => {
  const ready = await ensureFunasr();
  if (!ready) return null;

  sendSubtitleStatus('正在分析视频...');
  const ffprobe = path.join(FFMPEG_DIR, 'ffprobe.exe');
  const ffmpeg = path.join(FFMPEG_DIR, 'ffmpeg.exe');

  const duration = await new Promise((resolve) => {
    const p = spawn(ffprobe, ['-v', 'quiet', '-print_format', 'json', '-show_format', videoPath]);
    let out = '';
    p.stdout.on('data', d => out += d);
    p.on('close', () => {
      try { resolve(parseFloat(JSON.parse(out).format.duration) || 0); } catch(e) { resolve(0); }
    });
    p.on('error', () => resolve(0));
  });
  if (!duration) return null;

  const durationMin = Math.ceil(duration / 60);
  const segCount = Math.ceil(duration / SEGMENT_DURATION);
  const tmpDir = path.join(DOWNLOADS, '_tmp_segments');
  if (!fs.existsSync(tmpDir)) fs.mkdirSync(tmpDir, { recursive: true });

  let allText = '';
  let vtt = 'WEBVTT\n\n';

  for (let i = 0; i < segCount; i++) {
    const startSec = i * SEGMENT_DURATION;
    const segFile = path.join(tmpDir, `seg_${i}.wav`);

    sendSubtitleStatus(`正在提取音频片段 ${i + 1}/${segCount}（视�?${durationMin} 分钟）`);
    const extractOk = await new Promise((resolve) => {
      const p = spawn(ffmpeg, ['-y', '-ss', String(startSec), '-t', String(SEGMENT_DURATION), '-i', videoPath, '-vn', '-ar', '16000', '-ac', '1', '-f', 'wav', segFile]);
      p.on('close', code => resolve(code === 0));
      p.on('error', () => resolve(false));
    });
    if (!extractOk) continue;

    sendSubtitleStatus(`正在转录片段 ${i + 1}/${segCount}（视�?${durationMin} 分钟）`);

    // 确保服务还在（可能被上一段OOM杀了）
    const ok = await ensureFunasr();
    if (!ok) { try { fs.unlinkSync(segFile); } catch(e) {} continue; }

    const result = await transcribeFile(segFile);
    try { fs.unlinkSync(segFile); } catch(e) {}

    if (!result || !result.success || !result.text) continue;

    // 使用 funasr 返回的真实时间戳
    const text = result.text;
    const timestamps = result.timestamp || [];

    if (timestamps.length > 0) {
      // 按标点分句，用时间戳精确定位每句的起止时�?      const noSpace = text.replace(/\s/g, '');
      const sentenceEnds = /[.!?。！？]/g;
      // 在原文中按标点分句，保留空格
      let sentences = [];
      let lastPos = 0;
      let charCount = 0;
      for (let i = 0; i < text.length; i++) {
        if (/\s/.test(text[i])) continue;
        charCount++;
        if (/[.!?。！？]/.test(text[i])) {
          const s = text.slice(lastPos, i + 1).trim();
          const charEnd = charCount;
          const charStart = charEnd - s.replace(/\s/g, '').length;
          if (s) sentences.push({ text: s, charStart, charEnd });
          lastPos = i + 1;
        }
      }
      if (lastPos < text.length) {
        const s = text.slice(lastPos).trim();
        if (s) sentences.push({ text: s, charStart: charCount - s.replace(/\s/g, '').length, charEnd: charCount });
      }
      if (!sentences.length) sentences.push({ text, charStart: 0, charEnd: noSpace.length });

      const totalChars = noSpace.length;
      const totalTs = timestamps.length;

      for (const sent of sentences) {
        const tsStart = Math.floor(sent.charStart / totalChars * totalTs);
        const tsEnd = Math.min(Math.floor(sent.charEnd / totalChars * totalTs), totalTs - 1);
        const startMs = timestamps[tsStart] ? timestamps[tsStart][0] : 0;
        const endMs = timestamps[tsEnd] ? timestamps[tsEnd][1] : startMs + 1000;
        const start = fmtVTT(startSec + startMs / 1000);
        const end = fmtVTT(startSec + endMs / 1000);
        vtt += `${start} --> ${end}\n${sent.text}\n\n`;
      }
    } else {
      // 无时间戳回退：按文本长度估算
      const sentences = (text.match(/[^.!?。！？]+[.!?。！？]+/g) || [text]).map(s => s.trim()).filter(s => s.length > 0);
      if (!sentences.length) { allText += text; continue; }
      const segDur = Math.min(SEGMENT_DURATION, duration - startSec);
      const totalLen = sentences.reduce((a, s) => a + s.length, 0);
      let t = startSec;
      for (const s of sentences) {
        const seg = (s.length / totalLen) * segDur;
        const start = fmtVTT(t);
        t += seg;
        const end = fmtVTT(t);
        vtt += `${start} --> ${end}\n${s}\n\n`;
      }
    }
    allText += text;
  }

  // 清理临时目录
  try { fs.rmSync(tmpDir, { recursive: true }); } catch(e) {}

  if (!allText) { sendSubtitleStatus('语音识别失败'); return null; }

  const vttPath = videoPath.replace(/\.[^.]+$/, '.vtt');
  fs.writeFileSync(vttPath, vtt, 'utf-8');
  sendSubtitleStatus(`转录完成，共 ${segCount} 段`);
  return vttPath;
});

function fmtVTT(sec) {
  const h = Math.floor(sec / 3600), m = Math.floor((sec % 3600) / 60), s = sec % 60;
  return String(h).padStart(2,'0') + ':' + String(m).padStart(2,'0') + ':' + s.toFixed(3).padStart(6,'0');
}
